import React, { useState } from 'react';

const App = () => {
  const [products, setProducts] = useState([]);
  const [cart, setCart] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [categories, setCategories] = useState(['All', 'Electronics', 'Fashion']);
  const [selectedCategory, setSelectedCategory] = useState('All');

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="max-w-md mx-auto p-4 bg-white shadow-md rounded">
        <input type="search" className="block w-full p-2 pl-10 text-sm text-gray-700 focus:outline-none focus:ring-2 focus:ring-purple-600 focus:border-transparent" placeholder="Search" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
        <ul className="mt-4 space-y-4">
          {categories.map((category, index) => (
            <li key={index} className="inline-flex items-center text-gray-700 hover:text-gray-900">
              <input type="radio" className="mr-2 h-4 w-4" value={category} onChange={() => setSelectedCategory(category)} checked={selectedCategory === category} />
              <span className="text-sm">{category}</span>
            </li>
          ))}
        </ul>
        <ul className="mt-4 space-y-4">
          {products.map((product, index) => (
            <li key={index} className="flex items-center justify-between p-2 bg-gray-100 rounded">
              <img src="https://placehold.it/50" alt="Product Image" className="w-10 h-10 rounded-full object-cover" />
              <div className="flex-1 ml-4">
                <span className="text-sm font-medium">{product.name}</span>
                <span className="text-xs text-gray-600">{product.price}</span>
              </div>
              <button className="bg-red-500 hover:bg-red-700 text-white font-bold py-2 px-4 rounded">Add to Cart</button>
            </li>
          ))}
        </ul>
        <div className="bg-white p-4 border-t border-gray-200">
          <h3 className="text-lg font-bold text-gray-800">Shopping Cart</h3>
          <ul className="mt-4 space-y-4">
            {cart.map((item, index) => (
              <li key={index} className="flex items-center justify-between p-2 bg-gray-100 rounded">
                <span className="text-sm font-medium">{item.name}</span>
                <span className="text-xs text-gray-600">{item.price}</span>
                <button className="bg-red-500 hover:bg-red-700 text-white font-bold py-2 px-4 rounded">Remove</button>
              </li>
            ))}
          </ul>
          <p className="text-lg font-bold text-gray-800 mt-4">Total: {cart.reduce((acc, item) => acc + item.price, 0)}</p>
        </div>
      </div>
    </div>
  );
};

export default App;
